package main

import (
	"fmt"
	"os"

	"github.com/spf13/cobra"
)

func main() {
	var rootCmd = &cobra.Command{
		Use: "test",
		Run: func(cmd *cobra.Command, args []string) {
			fmt.Println("Command executed successfully")
		},
	}

	// Define flags
	rootCmd.Flags().String("flag1", "", "flag 1")
	rootCmd.Flags().String("flag2", "", "flag 2")
	rootCmd.Flags().String("flag3", "", "flag 3")
	rootCmd.Flags().String("flag4", "", "flag 4")
	rootCmd.Flags().String("flag5", "", "flag 5")

	// Require at least 2 flags from the group
	rootCmd.MarkFlagsAtLeast(2, "flag1", "flag2", "flag3", "flag4", "flag5")

	// Test case 1: Not enough flags set (should error)
	fmt.Println("Test 1: Only 1 flag set (should fail)")
	rootCmd.SetArgs([]string{"--flag1=value"})
	if err := rootCmd.Execute(); err != nil {
		fmt.Printf("Got expected error: %v\n\n", err)
	} else {
		fmt.Println("ERROR: Expected failure but command succeeded\n")
		os.Exit(1)
	}

	// Reset for next test
	rootCmd.SetArgs(nil)

	// Test case 2: Exactly 2 flags set (should pass)
	fmt.Println("Test 2: Exactly 2 flags set (should pass)")
	rootCmd.SetArgs([]string{"--flag1=value1", "--flag2=value2"})
	if err := rootCmd.Execute(); err != nil {
		fmt.Printf("ERROR: Got unexpected error: %v\n\n", err)
		os.Exit(1)
	}
	fmt.Println("SUCCESS: Command executed as expected\n")

	// Reset for next test
	rootCmd.SetArgs(nil)

	// Test case 3: More than 2 flags set (should pass)
	fmt.Println("Test 3: 3 flags set (should pass)")
	rootCmd.SetArgs([]string{"--flag1=value1", "--flag2=value2", "--flag3=value3"})
	if err := rootCmd.Execute(); err != nil {
		fmt.Printf("ERROR: Got unexpected error: %v\n\n", err)
		os.Exit(1)
	}
	fmt.Println("SUCCESS: Command executed as expected\n")

